document.addEventListener("DOMContentLoaded",()=>{"use strict";const e=document.querySelectorAll(".service-card"),t=(t,s)=>{if(s&&s.target.closest("a"))return;const a=t.classList.contains("is-expanded");e.forEach(e=>{e!==t&&(e.classList.remove("is-expanded"),e.setAttribute("aria-expanded","false"))}),a?(t.classList.remove("is-expanded"),t.setAttribute("aria-expanded","false")):(t.classList.add("is-expanded"),t.setAttribute("aria-expanded","true"))};e.forEach(e=>{e.addEventListener("click",s=>t(e,s)),e.addEventListener("keydown",s=>{if("Enter"===s.key||" "===s.key){if(s.target.closest("a"))return;s.preventDefault(),t(e,s)}})})});